-- 📌 성경 사전(Bible Dictionary) 샘플 데이터 삽입
INSERT INTO bible_dictionary (id, term, description, related_verses, created_at, updated_at)
VALUES (1, '은혜', '값없이 베푸는 하나님의 사랑과 호의. 구원과 일상 속 돌봄을 포함한다.', '에베소서 2:8-9, 요한복음 1:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (2, '믿음', '보이지 않는 하나님의 약속을 신뢰하고 의지하는 마음과 삶의 태도.', '히브리서 11:1, 로마서 10:17', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (3, '기도', '하나님께 마음을 드리며 감사, 간구, 찬양을 올려 드리는 대화.', '마태복음 6:9-13, 빌립보서 4:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (4, '회개', '잘못을 인정하고 하나님께 돌아서는 마음의 방향 전환.', '사도행전 3:19, 요한일서 1:9', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (5, '구원', '죄와 죽음에서 건짐 받아 하나님과 올바른 관계로 회복됨.', '로마서 6:23, 에베소서 2:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (6, '언약', '하나님과 사람 사이에 맺는 약속과 관계의 틀.', '창세기 9:9, 예레미야 31:33', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (7, '제자', '예수님을 따르며 배우고 삶으로 실천하는 사람.', '마태복음 28:19-20, 누가복음 9:23', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (8, '복음', '예수 그리스도를 통해 주어진 구원의 기쁜 소식.', '로마서 1:16, 고린도전서 15:3-4', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (9, '성령', '하나님의 영으로, 믿는 이 안에 거하며 인도하고 능력을 주신다.', '요한복음 14:26, 사도행전 1:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (10, '예배', '하나님께 경배와 찬양을 드리며 삶을 올려 드리는 행위.', '요한복음 4:24, 로마서 12:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (11, '사랑', '하나님과 이웃을 향한 헌신적이고 희생적인 마음.', '고린도전서 13:4-7, 요한일서 4:7', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (12, '소망', '하나님의 약속을 바라보며 현재를 견디는 믿음의 기대.', '로마서 15:13, 베드로전서 1:3', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (13, '교회', '예수 그리스도를 머리로 하는 믿는 자들의 공동체.', '마태복음 16:18, 에베소서 4:12', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (14, '안식', '하나님 안에서 누리는 쉼과 회복의 상태.', '히브리서 4:9-10, 출애굽기 20:8-10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (15, '섬김', '겸손히 이웃을 돕고 공동체를 세우는 태도.', '마가복음 10:45, 갈라디아서 5:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
